import { navigateStudio } from "../agentSessionChannel.js";
import { getConfig, hasCredentials } from "../config.js";
const args = process.argv.slice(2);
const sessionId = args[0];
const path = args[1];
if (!sessionId || !path) {
    console.error("Usage: navigateStudio <sessionId> <path>");
    process.exit(1);
}
if (!hasCredentials()) {
    console.error("Not authenticated.");
    process.exit(1);
}
const config = getConfig();
if (!config.apiKey) {
    console.error("No API key configured.");
    process.exit(1);
}
await navigateStudio({ serviceUrl: config.serviceUrl, apiKey: config.apiKey, sessionId }, path);
process.exit(0);
